import React, { useState, useEffect } from 'react';
import { Box, FormControl, FormLabel, Input, Button, Heading, useBreakpointValue, Text, Stack, Table, Thead, Tbody, Tr, Th, Td } from '@chakra-ui/react';
import { intervalToDuration } from 'date-fns';
import ReactSelect from 'react-select';
import axios from 'axios';

const QueueTaskTracker = () => {
  const [selectedQueue, setSelectedQueue] = useState(null);
  const [taskId, setTaskId] = useState('');
  const [taskLog, setTaskLog] = useState([]);
  const [startTime, setStartTime] = useState(null);
  const [timeElapsed, setTimeElapsed] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const [timeBeforePause, setTimeBeforePause] = useState(0);

  const queues = [
    'FH Discount Dispute',
    'MP Discount Dispute',
    'FH Pre-service Dispute',
    'MP Pre-service Dispute',
  ];

  const boxWidth = useBreakpointValue({ base: '90vw', md: '66vw' });
  const headingSize = useBreakpointValue({ base: 'md', md: 'lg' });
  const buttonSize = useBreakpointValue({ base: 'sm', md: 'md' });

  useEffect(() => {
    let timer;
    if (!isPaused && startTime) {
      timer = setInterval(() => {
        setTimeElapsed(((Date.now() - startTime) / 1000).toFixed(0));
      }, 1000);
    } else {
      clearInterval(timer);
    }
    return () => clearInterval(timer);
  }, [isPaused, startTime]);

  useEffect(() => {
    const fetchTasksForToday = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/tasks/today', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
          },
        });
        setTaskLog(response.data.tasks);
      } catch (error) {
        console.error('Error fetching todays tasks:', error);
      }
    };

    fetchTasksForToday();
  }, []);

  const handleQueueChange = (event) => {
    if (event) {
      setSelectedQueue(event);
      setStartTime(Date.now());
      setIsPaused(false);
      setTimeElapsed(0);
    }
  };

  const handleTaskComplete = async () => {
    if (taskId.trim() && selectedQueue) {
      const endTime = Date.now();
      const timeSpent = startTime ? ((endTime - startTime) / 1000).toFixed(2) : 'N/A';

      const newTask = {
        taskId,
        timeSpent,
        queue: selectedQueue.value,
        comment: '',
      };

      setTaskLog((prevLog) => [...prevLog, newTask]);

      try {
        console.log("Attempting to save task:", newTask);

        const response = await axios.post('http://localhost:5000/api/tasks', newTask, {
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
          },
        });

        if (response.status === 201) {
          const savedTask = response.data;
          setTaskLog((prevLog) =>
            prevLog.map((task, index) =>
              index === prevLog.length - 1 ? savedTask : task
            )
          );
          console.log('Task saved successfully:', savedTask);
        }
      } catch (error) {
        console.error('Error saving task:', error);
      }

      setTaskId('');
      setStartTime(Date.now());
    }
  };

  const handlePauseResume = () => {
    if (isPaused) {
      setStartTime(Date.now() - timeBeforePause);
      setIsPaused(false);
    } else {
      setTimeBeforePause(Date.now() - startTime);
      setIsPaused(true);
    }
  };

  const handleCommentChange = (i, v) => {
    setTaskLog((prevTaskLog) => {
      const updatedTaskLog = [...prevTaskLog];
      updatedTaskLog[i].comment = v;
      return updatedTaskLog;
    });
  };

  const formatTime = (seconds) => {
    if (seconds === 0 || seconds === 'N/A') return '0s';
    const duration = intervalToDuration({
      start: 0,
      end: seconds * 1000,
    });

    const hours = duration.hours;
    const minutes = duration.minutes;
    const secs = duration.seconds;

    return `${hours > 0 ? `${hours}h ` : ''}${minutes > 0 ? `${minutes}m ` : ''}${secs}s`;
  };

  return (
    <Box maxW={boxWidth} w={boxWidth} mx="auto" mt={10} p={5} borderWidth={1} borderRadius="lg">
      <Heading as="h3" size={headingSize} mb={4} textAlign="center">
        Task Tracker
      </Heading>

      <FormControl id="queue-selection" mb={4}>
        <FormLabel>Select Queue</FormLabel>
        <ReactSelect
          placeholder="Type Your Queue Name"
          value={selectedQueue}
          onChange={handleQueueChange}
          options={queues.map((queue) => ({ value: queue, label: queue }))}
          isSearchable
        />
      </FormControl>

      {selectedQueue && (
        <>
          <FormControl id="task-id" mb={4}>
            <FormLabel>Enter Task ID</FormLabel>
            <Input
              type="number"
              value={taskId}
              onChange={(e) => setTaskId(e.target.value)}
              placeholder="Enter Task ID"
            />
          </FormControl>

          {startTime && (
            <Text mt={4} my={6} fontWeight="bold">
              Time Spent on Current Task: {formatTime(timeElapsed)}
            </Text>
          )}

          <Stack direction={{ base: 'column', md: 'row' }} spacing={4}>
            <Button colorScheme="teal" size={buttonSize} onClick={handleTaskComplete}>
              Finish Task
            </Button>
            <Button colorScheme="teal" size={buttonSize} onClick={handlePauseResume}>
              {isPaused ? 'Resume Timer' : 'Pause Timer'}
            </Button>
          </Stack>
        </>
      )}

      <Box my={6} overflowX="auto">
        <Heading as="h4" size={headingSize} mb={4} textAlign="center">
          Task Log
        </Heading>
        <Table variant="simple" size="sm">
          <Thead>
            <Tr>
              <Th>Task ID</Th>
              <Th>Queue</Th>
              <Th>Time Spent</Th>
              <Th>Notes</Th>
            </Tr>
          </Thead>
          <Tbody>
            {taskLog.map((task, index) => (
              <Tr key={index}>
                <Td>{task.taskId}</Td>
                <Td>{task.queue}</Td>
                <Td>{formatTime(task.timeSpent)}</Td>
                <Td>
                  <Input
                    type="text"
                    placeholder="Add a comment"
                    value={task.comment || ''}
                    onChange={(e) => handleCommentChange(index, e.target.value)}
                    size={buttonSize}
                  />
                </Td>
              </Tr>
            ))}
          </Tbody>
        </Table>
      </Box>

      <Button colorScheme="blue" size={buttonSize} onClick={() => setIsPaused(true)}>
        End of Today
      </Button>
    </Box>
  );
};

export default QueueTaskTracker;
